const products = $('Google Sheets (Read)').all();
const imToken = $input.first().json.access_token;
const BATCH_SIZE = 50;
const batches = [];

for (let i = 0; i < products.length; i += BATCH_SIZE) {
  const batch = products.slice(i, i + BATCH_SIZE);

  // Build TDS XML with multiple skuList entries
  let lineNum = 0;
  const skuEntries = [];
  for (const p of batch) {
    const tdsSku = String(p.json['TDS SKU'] || '').trim();
    if (tdsSku) {
      lineNum++;
      skuEntries.push(
        '    <skuList>' +
        '<synnexSKU>' + tdsSku + '</synnexSKU>' +
        '<lineNumber>' + lineNum + '</lineNumber>' +
        '</skuList>'
      );
    }
  }

  const tdsXml =
    '<?xml version="1.0" encoding="UTF-8" ?>\n' +
    '<priceRequest>\n' +
    '  <customerNo>571788</customerNo>\n' +
    '  <userName>jim@gatortec.com</userName>\n' +
    '  <password>Yi-TqD22mzU_RW.h</password>\n' +
    skuEntries.join('\n') + '\n' +
    '</priceRequest>';

  // Build Ingram Micro products array
  const imProducts = [];
  for (const p of batch) {
    const imSku = String(p.json['INGRAM SKU'] || '').trim();
    if (imSku) {
      imProducts.push({ ingramPartNumber: imSku });
    }
  }
  const imBody = JSON.stringify({ products: imProducts });

  // Track products for result mapping
  const batchProducts = batch.map((p, idx) => ({
    rowIndex: i + idx + 2,
    sku: p.json['SKU'],
    tdsSku: String(p.json['TDS SKU'] || '').trim(),
    ingramSku: String(p.json['INGRAM SKU'] || '').trim()
  }));

  batches.push({
    json: {
      tdsXml,
      imBody,
      imToken,
      batchProducts,
      batchIndex: Math.floor(i / BATCH_SIZE)
    }
  });
}

return batches;

const tdsResponses = $input.all();
const allBatches = $('Code (Prepare Batches)').all();
const results = [];

for (let i = 0; i < tdsResponses.length; i++) {
  const response = String(tdsResponses[i].json.data || '');
  const batch = allBatches[i].json;
  const tdsInventory = {};

  // Parse each item block in TDS response
  const blockRegex = /<PriceAvailabilityList>[\s\S]*?<\/PriceAvailabilityList>/g;
  let block;

  while ((block = blockRegex.exec(response)) !== null) {
    const skuMatch = block[0].match(/<synnexSKU>(\S+?)<\/synnexSKU>/);
    if (!skuMatch) continue;

    const sku = skuMatch[1];
    let total = 0;

    // Sum warehouse quantities
    const qtyRegex = /<qty>(\d+)<\/qty>/g;
    let qtyMatch;
    while ((qtyMatch = qtyRegex.exec(block[0])) !== null) {
      total += parseInt(qtyMatch[1]) || 0;
    }

    tdsInventory[sku] = total;
  }

  results.push({
    json: {
      tdsInventory,
      imBody: batch.imBody,
      imToken: batch.imToken,
      batchProducts: batch.batchProducts
    }
  });
}

return results;

// n8n splits Ingram JSON array responses into individual items,
// so we can't match by index. Build global maps instead.

// 1. Build global IM inventory map from ALL split response items
const imItems = $input.all();
const imInventory = {};

for (const item of imItems) {
  const data = item.json;
  if (data && data.ingramPartNumber && data.availability) {
    imInventory[data.ingramPartNumber] = data.availability.totalAvailability || 0;
  }
}

// 2. Build global TDS inventory map from all batch parse results
const tdsBatches = $('Code (Parse TDS)').all();
const tdsInventory = {};

for (const batch of tdsBatches) {
  const batchInv = batch.json.tdsInventory || {};
  for (const [sku, qty] of Object.entries(batchInv)) {
    tdsInventory[sku] = qty;
  }
}

// 3. Get all products from batch metadata. Keep per-source qty so the
// parts list can show TDS / Ingram separately in the View modal.
const allBatches = $('Code (Prepare Batches)').all();
const combined = [];

for (const batch of allBatches) {
  for (const p of batch.json.batchProducts) {
    const tdsQty = (p.tdsSku && tdsInventory[p.tdsSku] != null) ? tdsInventory[p.tdsSku] : null;
    const imQty  = (p.ingramSku && imInventory[p.ingramSku] != null) ? imInventory[p.ingramSku] : null;
    combined.push({
      rowIndex: p.rowIndex,
      sku: p.sku,
      tdsQty,
      imQty,
      totalInventory: (tdsQty || 0) + (imQty || 0)
    });
  }
}

return [{ json: { combined } }];

const allBatches = $input.all();
const products = $('Google Sheets (Read)').all();
const totalRows = products.length;

// Flatten all batch results into rowIndex -> {total, tds, im} map
const inventoryMap = {};
for (const batch of allBatches) {
  for (const item of batch.json.combined) {
    inventoryMap[item.rowIndex] = {
      total: item.totalInventory,
      tds: item.tdsQty,
      im: item.imQty
    };
  }
}

// Build values array for column U (in row order) — sheet stores combined total
const values = [];
for (let row = 2; row <= totalRows + 1; row++) {
  const rec = inventoryMap[row];
  values.push([rec !== undefined ? rec.total : 0]);
}

const range = "'MarkIT CSV Setup'!U2:U" + (totalRows + 1);
const url = 'https://sheets.googleapis.com/v4/spreadsheets/1O8B7pBSvymC8NxR0grQIeJ38vFk0xhMLONIUFrPU2UQ/values/' + encodeURIComponent(range) + '?valueInputOption=RAW';

return [{ json: { url, body: JSON.stringify({ values }), totalRows, inventoryMap } }];

const products = $('Google Sheets (Read)').all();
const inventoryMap = $('Code (Prepare Sheet Update)').first().json.inventoryMap;

// CSV columns: all EXCEPT D (MSRP), E (Dealer B), S (TDS SKU), T (INGRAM SKU)
const includeKeys = [
  'Family', 'SKU', 'Price', 'Description', 'Screen Size', 'Color',
  'Processor', 'Memory', 'Storage', 'Power', 'Nano-Texture', 'Cellular',
  'Ethernet', 'Keyboard', 'Moveability', 'Stocked'
];
const headers = [...includeKeys, 'Inventory'];

function escapeCSV(val) {
  const str = String(val === null || val === undefined ? '' : val).replace(/\r/g, '').replace(/[\u2010\u2011\u2012\u2013\u2014\u2015\uFE58\uFE63\uFF0D]/g, '-');
  if (str.includes(',') || str.includes('"') || str.includes('\n')) {
    return '"' + str.replace(/"/g, '""') + '"';
  }
  return str;
}

const rows = [headers.map(escapeCSV).join(',')];

for (let i = 0; i < products.length; i++) {
  const p = products[i].json;
  const rowIndex = i + 2;
  const inventory = inventoryMap[rowIndex] !== undefined ? inventoryMap[rowIndex] : 0;

  const values = includeKeys.map(key => {
    if (key === 'Price' && p[key] !== '' && p[key] !== null && p[key] !== undefined) {
      return escapeCSV(Number(p[key]).toFixed(2));
    }
    return escapeCSV(p[key]);
  });
  values.push(escapeCSV(inventory));
  rows.push(values.join(','));
}

const csv = rows.join('\n');
const base64 = Buffer.from(csv, 'utf-8').toString('base64');

const today = new Date();
const dateStr = String(today.getMonth() + 1).padStart(2, '0') + '-' +
  String(today.getDate()).padStart(2, '0') + '-' + today.getFullYear();

return [{
  json: { dateStr },
  binary: {
    data: {
      data: base64,
      mimeType: 'text/csv',
      fileName: 'GatorTec-Apple-Inventory-' + dateStr + '.csv',
      fileExtension: 'csv'
    }
  }
}];

// Build the parts.json payload for the staff lookup page.
const products = $('Google Sheets (Read)').all();
const inventoryMap = $('Code (Prepare Sheet Update)').first().json.inventoryMap || {};

function num(v) {
  if (v == null || v === '') return null;
  const cleaned = String(v).replace(/[^0-9.\-]/g, '');
  const n = parseFloat(cleaned);
  return Number.isFinite(n) ? n : null;
}
function str(v) {
  if (v == null) return null;
  const s = String(v).trim();
  return s === '' ? null : s;
}

const items = [];
for (let i = 0; i < products.length; i++) {
  const p = products[i].json;
  const sku = str(p['SKU']);
  if (!sku) continue;

  const rowIndex = i + 2;
  const rec = inventoryMap[rowIndex];

  items.push({
    SKU: sku,
    Family: str(p['Family']),
    Description: str(p['Description']),
    MSRP: num(p['MSRP']),
    DealerB: num(p['Dealer B']),
    ScreenSize: str(p['Screen Size']),
    Color: str(p['Color']),
    Processor: str(p['Processor']),
    Memory: str(p['Memory']),
    Storage: str(p['Storage']),
    Power: str(p['Power']),
    NanoTexture: str(p['Nano-Texture']),
    Cellular: str(p['Cellular']),
    Ethernet: str(p['Ethernet']),
    Keyboard: str(p['Keyboard']),
    Moveability: str(p['Moveability']),
    Stocked: str(p['Stocked']),
    TDS_SKU: str(p['TDS SKU']),
    INGRAM_SKU: str(p['INGRAM SKU']),
    Inventory: (rec && typeof rec === 'object') ? rec.total : (rec != null ? rec : 0),
    TDS_Inventory: (rec && typeof rec === 'object' && rec.tds != null) ? rec.tds : null,
    INGRAM_Inventory: (rec && typeof rec === 'object' && rec.im != null) ? rec.im : null,
  });
}

const payload = {
  _meta: {
    generated_at: new Date().toISOString(),
    source: 'MarkIT CSV Setup tab \u2014 daily refresh via n8n',
    count: items.length,
  },
  items
};

const today = new Date();
const dateStr = String(today.getMonth() + 1).padStart(2, '0') + '-' +
  String(today.getDate()).padStart(2, '0') + '-' + today.getFullYear();

return [{
  json: {
    parts_json: JSON.stringify(payload, null, 2),
    count: items.length,
    dateStr
  }
}];

const error = $input.first().json;

const nodeName = error.execution?.lastNodeExecuted || 'Unknown node';
const errorMsg = error.execution?.error?.message || 'Unknown error';
const workflowName = error.workflow?.name || 'MarkIT Inventory Report';
const executionId = error.execution?.id || 'N/A';

const today = new Date();
const dateStr = String(today.getMonth() + 1).padStart(2, '0') + '-' +
  String(today.getDate()).padStart(2, '0') + '-' + today.getFullYear();
const timeStr = today.toLocaleTimeString('en-US');

const body = 'The workflow "' + workflowName + '" failed on ' + dateStr + ' at ' + timeStr + '.\n\n' +
  'Failed Node: ' + nodeName + '\n' +
  'Error: ' + errorMsg + '\n' +
  'Execution ID: ' + executionId + '\n\n' +
  'Please check the n8n dashboard for full details.';

return [{ json: { subject: 'ALERT: MarkIT Inventory Report Failed - ' + dateStr, body } }];
